var first = $input.first();
var item = (first && first.json) ? first.json : {};

var triggerNode = $node['Telegram Trigger'];
var triggerJson = (triggerNode && triggerNode.json) ? triggerNode.json : {};

var message = triggerJson.message || triggerJson.edited_message || item.message || item.edited_message || {};
var text = String(message.text || '').trim();
var chatId = (message.chat && message.chat.id) ? message.chat.id : null;
var telegramUserId = (message.from && message.from.id) ? message.from.id : null;
var telegramUsername = (message.from && message.from.username) ? message.from.username : null;

var appBaseUrl = String(item.appBaseUrl || '').trim();
if (appBaseUrl.length > 1 && appBaseUrl.charAt(appBaseUrl.length - 1) === '/') {
  appBaseUrl = appBaseUrl.slice(0, -1);
}
var claimSecret = String(item.claimSecret || '').trim();

if (!text) {
  return [];
}

if (text.indexOf('/start') !== 0) {
  return [];
}

var payload = text.replace(/^\/start\s*/, '').trim();
var parts = payload.split('_');
if (parts.length < 3 || parts[0] !== 'login') {
  return [{ json: { action: 'help', chatId: chatId, telegramUserId: telegramUserId, telegramUsername: telegramUsername, text: 'Usa el boton de la app para iniciar el login.' } }];
}

if (!appBaseUrl || !claimSecret || appBaseUrl.indexOf('TU-HOST') !== -1 || claimSecret.indexOf('PEGA_AQUI') !== -1) {
  return [{ json: { action: 'help', chatId: chatId, telegramUserId: telegramUserId, telegramUsername: telegramUsername, text: 'Configura appBaseUrl y claimSecret en el nodo Configuracion.' } }];
}

var challengeToken = parts[1];
var otpCode = parts.slice(2).join('_');

return [{
  json: {
    action: 'claim',
    chatId: chatId,
    telegramUserId: telegramUserId,
    telegramUsername: telegramUsername,
    telegramChatId: chatId,
    challengeToken: challengeToken,
    otpCode: otpCode,
    appBaseUrl: appBaseUrl,
    claimSecret: claimSecret
  }
}];
